# [leetcode-2488. 统计中位数为 K 的子数组](https://leetcode.cn/problems/count-subarrays-with-median-k/)
```C++
class Solution {
public:
    int countSubarrays(vector<int>& nums, int k) {
        vector<int> sign = vector(nums.size() + 1, 0);
        unordered_map<int,int> sum;
        bool isK = false;
        int result = 0;

        sum[0]++;
        for(int i = 1; i <= nums.size(); i++)
        {

            if(nums[i - 1] > k)
            sign[i] = sign[i - 1] + 1;
            else if(nums[i - 1] < k)
            sign[i] = sign[i - 1] + -1;
            else
            {
                sign[i] = sign[i - 1];
                isK = true;
            }
            if(isK)
            {
                result += sum[sign[i]];
                result += sum[sign[i] - 1];
            }
            else
            sum[sign[i]]++;

            //cout << sign[i] << endl;
        }
        return result;
    }
};
```

要使子数组的中位数为k，那么必须符合下列两个条件之一：

- 比k大的数和比k小的数，数量一样多。
- 比k大的数比比k小的数多一个。

那么把数组作如下处理，比k大的数，标注为1；比k小的数，标注为-1；k标记为0。

然后计算前缀和，可以把前缀和认为的“高度”，数组的标记（-1、0、1）是“坡度”。符合条件的子数组，数组的头和数组的尾，“高度”和前面的两个条件对应，只有两种情况：

- 头尾高度相等。
- 尾的高度比头高1。

头的索引必然小于等于k的索引，尾的索引必然大于等于k的索引（因为子数组必然包含k）。

把可能的头的“高度”记录在一个哈希表中，每有一个尾，只要找到可能的头，结果就加一。

时间复杂度$O(n)$。

空间复杂度$O(n)$。

# [leetcode-1615. 最大网络秩](https://leetcode.cn/problems/maximal-network-rank/description/)

使用了枚举的办法，时间复杂度$O(n^2)$。

```C++
class Solution {
public:
    int maximalNetworkRank(int n, vector<vector<int>>& roads) {
        vector<vector<int>> rd = vector(n,vector(n,0));
        vector<int> roadNum = vector(n,0);
        for(vector<int> road : roads)
        {
            rd[min(road[0],road[1])][max(road[0],road[1])] = 1;
            roadNum[road[0]]++;
            roadNum[road[1]]++;
        }

        int maxrank = 0;
        for (int i = 0; i < n; i++) 
        {
            for (int j = i + 1; j < n; j++) {
                int rank =  roadNum[i] + roadNum[j] - rd[i][j];
                maxrank = max(maxrank,rank);
            }
        }

        return maxrank;
    }
};

```

也可以用贪心的办法解决，官方题解代码如下：

```C++
class Solution {
public:
    int maximalNetworkRank(int n, vector<vector<int>>& roads) {
        vector<vector<bool>> connect(n, vector<bool>(n, false));
        vector<int> degree(n);
        for (auto road : roads) {
            int x = road[0], y = road[1];
            connect[x][y] = true;
            connect[y][x] = true;
            degree[x]++;
            degree[y]++;
        }

        int first = -1, second = -2;
        vector<int> firstArr, secondArr;
        for (int i = 0; i < n; ++i) {
            if (degree[i] > first) {
                second = first;
                secondArr = firstArr;
                first = degree[i];
                firstArr.clear();
                firstArr.emplace_back(i);
            } else if (degree[i] == first) {
                firstArr.emplace_back(i);
            } else if (degree[i] > second){
                secondArr.clear();
                second = degree[i];
                secondArr.emplace_back(i);
            } else if (degree[i] == second) {
                secondArr.emplace_back(i);
            }
        }
        if (firstArr.size() == 1) {
            int u = firstArr[0];
            for (int v : secondArr) {
                if (!connect[u][v]) {
                    return first + second;
                }
            }
            return first + second - 1;
        } else {
            int m = roads.size();
            if (firstArr.size() * (firstArr.size() - 1) / 2 > m) {
                return first * 2;
            }
            for (int u: firstArr) {
                for (int v: firstArr) {
                    if (u != v && !connect[u][v]) {
                        return first * 2;
                    }
                }
            }
            return first * 2 - 1;
        }
    }
};
```
时间复杂度为$O(m+n)$。

